#include<bits/stdc++.h>
using namespace std;

double a[1005];

int main()
{
	int n,i,m,j;
	double pj,max=0,s=0,maxn=0,mina=11;
	scanf("%d%d",&n,&m);
	for(i=1;i<=n;i++)
	{
		for(j=1;j<=m;j++)
		{
			scanf("%lf",&a[j]);
			if(a[j]>maxn)
			{
				maxn=a[j];
			}
			if(a[j]<mina)
			{
				mina=a[j];
			}
			s+=a[j];
		}
		pj=(s-maxn-mina)/(m-2);
		s=0;
		if(pj>max)
		{
			max=pj;
		}
		maxn=0;
		mina=11;
	}
	printf("%0.2lf",max);
	return 0;
}
